SELECT session_id, total_files_scanned, files_fully_indexed
FROM indexing_sessions
ORDER BY total_files_scanned DESC;

SELECT session_id, total_files_scanned
FROM indexing_sessions
ORDER BY total_files_scanned DESC;

SELECT provider_name
FROM indexing_providers
ORDER BY provider_name ASC;

SELECT session_id, SUM(files_fully_indexed) AS total_files_fully_indexed
FROM indexing_sessions
GROUP BY session_id;

SELECT DISTINCT provider_id
FROM indexing_sessions
WHERE session_end_time = (SELECT MAX(session_end_time) FROM indexing_sessions);
